              verifyAndUpdate(clientSessionID);   //Verify and Update the current Client’s Cookie. This method will check if Session cookie is valid or not    }      chain.doFilter(req, res ,chain );  }       private void SetCookies (HttpServletResponse response, String clientIpAddress) throws IOException {    
            String sessionId = SESSION_ID_HASH.newHasher().putString(clientIpAddress).hash().toString();   //creates a hash of IP address to generate the Session ID and set it as cookie value – this will be unique per user on your site, preventing multiple users from logging in with same credentials
            Cookie sessionCookie = new Cookie (COOKIE_NAME ,sessionId);    //Create A New Instance Of The class COokiE     which is used to create a cookie. Set the name and value of this cooKIe –this will be unique for every user on our site
            sessionCookie .setPath(PATH );   //Set Path For Cookies -usually root directory but can also include sub directories if necessary e,g., /users/sessioncookiename etc... This should match with where the cookies are stored (e.g a specific file or database table) – this will be determined by your web server configuration
            sessionCookie .setMaxAge(COOKIE_EXPIRY); //Set Max Age of Cookies -the value could also depend on user requirements/chosen policy e,g., after x hours inactivity. I have kept it as per instruction a bit creative – this will be determined by your web server configuration
            response .addCookie(sessionCookie );   //Add the cookies to HttpServletResponse (This line of code is used for sending cookie back in responses)    }     private void verifyAndUpdate (@Param("clientSessionID") String clientIpAddress ) throws IOException, ParseException {  Cookie sessioncookies[] = request .getCookies();   //Get All the cookies sent by users to our service (This line of code fetches all information about current user’s sessions)
